-- 來源：frontend/data/commerce/orders.json 的 222 筆訂單，加上正式 Firebase 測試會員的 3 筆固定隨機訂單。
-- 訂單明細會建立可追溯的商城庫存保留，但不建立無法還原 variant 與員工的舊庫存異動。
-- 225 筆訂單皆為 discount=0，且沒有 coupon claim／券快照來源，因此刻意不建立 order_coupons。
ON CONFLICT (id) DO UPDATE SET
    customer_id = EXCLUDED.customer_id,
    buyer_name_snapshot = EXCLUDED.buyer_name_snapshot,
    buyer_email_snapshot = EXCLUDED.buyer_email_snapshot,
    recipient_name_snapshot = EXCLUDED.recipient_name_snapshot,
    shipping_address_snapshot = EXCLUDED.shipping_address_snapshot,
    shipping_phone_snapshot = EXCLUDED.shipping_phone_snapshot,
    subtotal = EXCLUDED.subtotal,
    shipping_fee = EXCLUDED.shipping_fee,
    discount = EXCLUDED.discount,
    total = EXCLUDED.total,
    payment_method = EXCLUDED.payment_method,
    payment_status = EXCLUDED.payment_status,
    refund_status = EXCLUDED.refund_status,
    status = EXCLUDED.status,
    placed_at = EXCLUDED.placed_at,
    paid_at = EXCLUDED.paid_at,
    updated_at = EXCLUDED.updated_at;

ON CONFLICT (id) DO UPDATE SET
    order_id = EXCLUDED.order_id,
    product_id = EXCLUDED.product_id,
    variant_id = EXCLUDED.variant_id,
    sku_snapshot = EXCLUDED.sku_snapshot,
    product_name_snapshot = EXCLUDED.product_name_snapshot,
    specification_snapshot = EXCLUDED.specification_snapshot,
    brand_name_snapshot = EXCLUDED.brand_name_snapshot,
    image_url_snapshot = EXCLUDED.image_url_snapshot,
    unit_price_snapshot = EXCLUDED.unit_price_snapshot,
    quantity = EXCLUDED.quantity;

ON CONFLICT (id) DO UPDATE SET
    order_id = EXCLUDED.order_id,
    status = EXCLUDED.status,
    occurred_at = EXCLUDED.occurred_at,
    actor_id = EXCLUDED.actor_id,
    note = EXCLUDED.note;

ON CONFLICT (id) DO UPDATE SET
    source_history_id = EXCLUDED.source_history_id,
    order_id = EXCLUDED.order_id,
    event_type = EXCLUDED.event_type,
    occurred_at = EXCLUDED.occurred_at,
    actor_id = EXCLUDED.actor_id,
    note = EXCLUDED.note;

-- 舊訂單沒有出貨倉欄位，Seed 以前端固定商城主倉 main 作為穩定履約庫位。
-- 已付款或 COD 的 unshipped 訂單保持 active；逾時未付 ECPay 訂單為 expired；其餘已出貨交易為 fulfilled。
    id,
    order_item_id,
    variant_id,
    location_id,
    quantity,
    status,
    idempotency_key,
    reserved_at,
    expires_at,
    released_at,
    fulfilled_at,
    inventory_domain
) OVERRIDING SYSTEM VALUE
SELECT
    7600000 + item.id,
    item.id,
    item.variant_id,
    'main',
    item.quantity,
    CASE
        WHEN order_header.status = 'unshipped'
             AND order_header.payment_status = 'unpaid'
             AND order_header.payment_method = 'ecpay-credit' THEN 'expired'
        WHEN order_header.status = 'unshipped' THEN 'active'
        ELSE 'fulfilled'
    END,
    'seed-order-item-' || item.id,
    order_header.placed_at,
    CASE
        WHEN order_header.status = 'unshipped'
             AND order_header.payment_status = 'unpaid'
             AND order_header.payment_method = 'ecpay-credit'
            THEN order_header.placed_at + INTERVAL '15 minutes'
        ELSE NULL
    END,
    CASE
        WHEN order_header.status = 'unshipped'
             AND order_header.payment_status = 'unpaid'
             AND order_header.payment_method = 'ecpay-credit'
            THEN order_header.placed_at + INTERVAL '15 minutes'
        ELSE NULL
    END,
    CASE
        WHEN order_header.status <> 'unshipped' THEN COALESCE(
            (
                SELECT min(history.occurred_at)
                FROM public.order_status_history history
                WHERE history.order_id = order_header.id
                  AND history.status = 'shipped'
            ),
            order_header.updated_at
        )
        ELSE NULL
    END,
    'store'
FROM public.order_items item
JOIN public.orders order_header ON order_header.id = item.order_id
WHERE order_header.id ~ '^[0-9]+$'
  AND order_header.id::integer BETWEEN 1 AND 225
ON CONFLICT (id) DO UPDATE SET
    order_item_id = EXCLUDED.order_item_id,
    variant_id = EXCLUDED.variant_id,
    location_id = EXCLUDED.location_id,
    quantity = EXCLUDED.quantity,
    status = EXCLUDED.status,
    idempotency_key = EXCLUDED.idempotency_key,
    reserved_at = EXCLUDED.reserved_at,
    expires_at = EXCLUDED.expires_at,
    released_at = EXCLUDED.released_at,
    fulfilled_at = EXCLUDED.fulfilled_at,
    inventory_domain = EXCLUDED.inventory_domain;

-- 商城標籤：依非取消、非退貨訂單的商品數量總和，重新標記前 6 件熱銷商品。
DELETE FROM public.equipment_tags
WHERE tag = '熱銷';

SELECT bestseller.item_id, '熱銷'
FROM (
    SELECT product.item_id
    FROM public.products product
    JOIN public.equipment_items item ON item.id = product.item_id
    JOIN public.order_items order_item ON order_item.product_id = product.id
    JOIN public.orders order_header ON order_header.id = order_item.order_id
    WHERE product.status = 'active'
      AND item.active = true
      AND order_header.status NOT IN ('cancelled', 'returned')
      AND EXISTS (
          SELECT 1
          FROM public.product_variants variant
          WHERE variant.product_id = product.id
            AND variant.status = 'active'
      )
    GROUP BY product.id, product.item_id
    ORDER BY sum(order_item.quantity) DESC, product.id ASC
    LIMIT 6
) bestseller
ON CONFLICT (item_id, tag) DO NOTHING;

SELECT setval('public.order_items_id_seq', GREATEST((SELECT max(id) FROM public.order_items), 1), true);
SELECT setval('public.order_status_history_id_seq', GREATEST((SELECT max(id) FROM public.order_status_history), 1), true);
SELECT setval('public.order_event_history_id_seq', GREATEST((SELECT max(id) FROM public.order_event_history), 1), true);
SELECT setval('public.product_stock_reservations_id_seq', GREATEST((SELECT max(id) FROM public.product_stock_reservations), 1), true);
